exercises.solution:
const { EventEmitter } = require('events');

class Countdown extends EventEmitter {
  start(n) {
    for (let i = n; i >= 1; i--) {
      this.emit('tick', i);
    }
    this.emit('done');
  }
}

const cd = new Countdown();
cd.on('tick', (num) => console.log(`Tick: ${num}`));
cd.on('done', () => console.log('Done!'));
cd.start(3);

